"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["8226"],{44865(s){s.exports=JSON.parse('{"tag":{"label":"system","permalink":"/sysanalyst-kb.github.io/docs/tags/system","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":2,"items":[{"id":"specialization/govtech-gis-architecture","title":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0413\u0418\u0421 \u2014 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u0413\u0418\u0421 (\u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430) \u2014 \u0418\u0421 \u0434\u043B\u044F \u043E\u043A\u0430\u0437\u0430\u043D\u0438\u044F \u0433\u043E\u0441\u0443\u0441\u043B\u0443\u0433, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0433\u043E\u0441\u0444\u0443\u043D\u043A\u0446\u0438\u0439 \u0438\u043B\u0438 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F. \u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0413\u0418\u0421 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0415\u041F\u0413\u0423 (110M+ \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439), \u0413\u0418\u0421 \u0413\u041C\u041F (500M+ \u043F\u043B\u0430\u0442\u0435\u0436\u0435\u0439/\u0433\u043E\u0434), \u0415\u0413\u0418\u0421\u0421\u041E (100M+ \u0437\u0430\u043F\u0438\u0441\u0435\u0439).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-gis-architecture"},{"id":"specialization/medtech-mis","title":"\u041C\u0418\u0421 \u2014 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u041C\u0418\u0421 (\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0430\u044F \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430) \u2014 \u043E\u0441\u043D\u043E\u0432\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0431\u043E\u043B\u044C\u043D\u0438\u0446\u044B \u0438\u043B\u0438 \u043F\u043E\u043B\u0438\u043A\u043B\u0438\u043D\u0438\u043A\u0438. \u041E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u042D\u041C\u041A, \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u0435, \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u044E, \u0440\u0430\u0434\u0438\u043E\u043B\u043E\u0433\u0438\u044E, \u0430\u043F\u0442\u0435\u043A\u0443, \u043E\u0442\u0447\u0451\u0442\u043D\u043E\u0441\u0442\u044C \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u0415\u0413\u0418\u0421\u0417. \u041A\u043B\u044E\u0447\u0435\u0432\u043E\u0439 \u0432\u044B\u0437\u043E\u0432: \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0439 (10+ \u043F\u043E\u0434\u0441\u0438\u0441\u0442\u0435\u043C) \u0438 compliance (323-\u0424\u0417, 152-\u0424\u0417). \u041A\u0440\u0443\u043F\u043D\u0435\u0439\u0448\u0430\u044F \u041C\u0418\u0421 \u0420\u0424 \u2014 \u0415\u041C\u0418\u0410\u0421 \u041C\u043E\u0441\u043A\u0432\u044B \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442 100M+ \u0437\u0430\u043F\u0438\u0441\u0435\u0439/\u0433\u043E\u0434.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-mis"}],"unlisted":false}}')}}]);